-- Province: Jawa Barat
INSERT INTO formasi_pages (slug, page_type, province, province_slug, title, meta_description, target_keywords, content_blocks, formations_data, total_quota, total_institutions, has_placeholder_data, data_source, created_at, updated_at) VALUES (
  'jawa-barat',
  'province',
  'Jawa Barat',
  'jawa-barat',
  'Formasi CPNS Jawa Barat 2024 — Instansi, Kuota & Persyaratan',
  'Info lengkap formasi CPNS Jawa Barat: instansi, kuota, persyaratan, dan cara daftar. Data terbaru 2024.',
  '{"formasi cpns jawa-barat","cpns jawa-barat","formasi cpns jawa-barat 2024","lowongan cpns jawa-barat"}',
  '[{"type":"paragraph","text":"Pendaftaran CPNS Jawa Barat membuka peluang besar bagi lulusan SMA, D3, dan S1. Berdasarkan formasi terakhir, berbagai instansi pusat dan daerah membuka lowongan dengan persyaratan yang bervariasi."},{"type":"paragraph","text":"Informasi formasi CPNS Jawa Barat meliputi kuota per instansi, jabatan yang tersedia, tingkat pendidikan yang dibutuhkan, serta persyaratan khusus tertentu. Data ini berdasarkan pengumuman resmi CPNS terakhir dan akan diperbarui saat ada pengumuman baru."},{"type":"heading","level":2,"text":"Daftar Formasi per Instansi"},{"type":"paragraph","text":"Berikut adalah daftar instansi yang membuka formasi CPNS di Jawa Barat. Data menunjukkan total kuota dan jenis jabatan yang tersedia. [DATA_PLACEHOLDER: Tabel formasi akan diperbarui dengan data BKN terbaru]"},{"type":"heading","level":2,"text":"Formasi per Kota/Kabupaten"},{"type":"paragraph","text":"Formasi CPNS Jawa Barat tersebar di beberapa kota/kabupaten utama: Bandung, Bekasi, Depok. Masing-masing lokasi memiliki karakteristik formasi yang berbeda tergantung kebutuhan instansi di wilayah tersebut."},{"type":"heading","level":2,"text":"Persyaratan Umum CPNS"},{"type":"list","ordered":false,"items":["Warga Negara Indonesia (WNI)","Usia minimal 18 tahun dan maksimal 35 tahun","Sehat jasmani dan rohani (dibuktikan dengan surat keterangan dokter)","Tidak pernah dijatuhi hukuman pidana penjara","Tidak pernah diberhentikan sebagai CPNS/PNS","Pendidikan sesuai dengan formasi yang dilamar"]},{"type":"heading","level":2,"text":"Alur Pendaftaran CPNS"},{"type":"list","ordered":true,"items":["Buat akun di portal SSCASN (sscasn.bkn.go.id)","Pilih instansi dan formasi yang diminati","Unggah dokumen persyaratan","Tunggu pengumuman seleksi administrasi","Ikuti Seleksi Kompetensi Dasar (SKD) jika lolos administrasi","Ikuti Seleksi Kompetensi Bidang (SKB) jika lolos SKD","Pengumuman akhir dan pengangkatan"]},{"type":"heading","level":2,"text":"Tips Lolos CPNS"},{"type":"paragraph","text":"Persiapkan dokumen dengan teliti sebelum upload. Pastikan semua berkas sesuai format dan ukuran yang ditentukan. Perhatikan deadline pendaftaran dan jangan menunggu hari terakhir."},{"type":"heading","level":2,"text":"Setelah lolos administrasi, tahap berikutnya adalah SKD (Seleksi Kompetensi Dasar) berbasis CAT. Di sinilah mayoritas peserta gagal meski telah melewati seleksi berkas. Persiapkan diri dari sekarang dengan latihan soal SKD yang simulasi sesuai standar BKN."},{"type":"cta","style":"hard"},{"type":"paragraph","text":"Data formasi di atas bersumber dari pengumuman CPNS 2024 terakhir. Data akan diperbarui ketika ada pengumuman formasi CPNS Jawa Barat periode berikutnya."}]'::jsonb,
  '[]'::jsonb,
  0,
  0,
  true,
  'Template',
  NOW(),
  NOW()
);

